import{_ as t,o as a,c as e,ai as r}from"./chunks/framework.DMjte4z8.js";const d=JSON.parse('{"title":"触发器内存泄漏处理","description":"","frontmatter":{"title":"触发器内存泄漏处理","category":"triggers","updated":"2026-05-08T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.86,"discovered_via":"manual","sources":["https://www.thehelper.net/threads/floating-text-leaks.129373/","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=27219"]},"headers":[],"relativePath":"triggers/触发器内存泄漏处理.md","filePath":"triggers/触发器内存泄漏处理.md","lastUpdated":1778216780000}'),s={name:"triggers/触发器内存泄漏处理.md"};function l(n,o,i,p,u,h){return a(),e("div",null,[...o[0]||(o[0]=[r(`<h1 id="触发器内存泄漏处理" tabindex="-1">触发器内存泄漏处理 <a class="header-anchor" href="#触发器内存泄漏处理" aria-label="Permalink to “触发器内存泄漏处理”">​</a></h1><h2 id="什么是触发器内存泄漏" tabindex="-1">什么是触发器内存泄漏 <a class="header-anchor" href="#什么是触发器内存泄漏" aria-label="Permalink to “什么是触发器内存泄漏”">​</a></h2><p>本节将向你介绍什么是内存泄漏，以及为什么它会让你的地图变得越来越卡。你会理解触发器在后台默默消耗&quot;内存&quot;的原理，为后续学习如何修复泄漏打下基础。</p><h3 id="内存泄漏的基本概念" tabindex="-1">内存泄漏的基本概念 <a class="header-anchor" href="#内存泄漏的基本概念" aria-label="Permalink to “内存泄漏的基本概念”">​</a></h3><p><strong>什么是&quot;内存&quot;？</strong> 想象你的电脑是一间大仓库，内存就是仓库里暂时存放物品的空间。当你的地图运行时，游戏会把各种数据（比如单位、对话框、浮动文字）放进这个&quot;仓库&quot;里暂存。</p><p><strong>什么是内存泄漏？</strong> 正常情况下，东西用完会被&quot;扔掉&quot;，仓库空间会空出来。但如果有bug，某些用完的东西没有被扔掉，还一直占着仓库空间——这就叫<strong>内存泄漏</strong>。就像你网购拆完快递，纸箱一直堆在客厅不扔掉，迟早客厅就满了。</p><h3 id="为什么触发器会产生内存泄漏" tabindex="-1">为什么触发器会产生内存泄漏 <a class="header-anchor" href="#为什么触发器会产生内存泄漏" aria-label="Permalink to “为什么触发器会产生内存泄漏”">​</a></h3><p>触发器（Trigger）是地图中执行各种功能的&quot;自动化程序&quot;。每次触发器运行，它可能会<strong>创建</strong>一些看不见的资源，比如浮动文字效果（Floating Text）[^1]。</p><p><strong>问题出在哪里？</strong> 触发器创建了这些资源后，必须在用完时&quot;销毁&quot;它们，把内存还回去。但很多初学者写触发器时，<strong>只管创建，不管销毁</strong>。时间一长，泄漏的资源越堆越多，你的电脑仓库就越来越满了。</p><p>常见容易泄漏的触发器元素包括：</p><ul><li>浮动文字效果</li><li>单位组（Groups of Units）</li><li>特效（Effects）</li><li>对话框（Dialogs）</li></ul><h3 id="内存泄漏对地图的影响" tabindex="-1">内存泄漏对地图的影响 <a class="header-anchor" href="#内存泄漏对地图的影响" aria-label="Permalink to “内存泄漏对地图的影响”">​</a></h3><ol><li><strong>性能逐渐下降</strong> — 地图刚打开时运行流畅，玩着玩着越来越卡</li><li><strong>内存占用不断增加</strong> — 打开Windows任务管理器，能看到游戏进程内存越来越大</li><li><strong>严重时会崩溃</strong> — 内存用尽后，游戏直接卡死或闪退</li><li><strong>所有玩家都会受影响</strong> — 多人游戏中，泄漏会让所有玩家电脑变卡</li></ol><blockquote><p><strong>💡 新手提示</strong>：内存泄漏是&quot;慢性病&quot;，一开始你可能感觉不到。但一场10分钟的局可能泄漏成百上千个对象，所以要<strong>从一开始就养成好习惯</strong>，每次创建都要想着怎么销毁。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为&quot;触发器执行完了，里面的变量就自动没了&quot;。错！触发器里的<strong>局部变量</strong>用完会消失，但<strong>全局变量</strong>和<strong>触发器创建的资源</strong>（如浮动文字）不会自动清理，必须手动写代码销毁。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>现在你明白了：</p><ul><li>内存就像电脑的&quot;临时仓库&quot;</li><li>内存泄漏就是资源用完没清理，占着空间不释放</li><li>触发器创建浮动文字、单位组等资源时，如果忘记销毁，就会导致泄漏</li><li>泄漏会让地图越玩越卡，最终可能崩溃</li></ul><p>掌握这个概念后，你就已经比很多新手更懂得如何写出&quot;健康&quot;的地图了！</p><h2 id="常见的内存泄漏来源" tabindex="-1">常见的内存泄漏来源 <a class="header-anchor" href="#常见的内存泄漏来源" aria-label="Permalink to “常见的内存泄漏来源”">​</a></h2><p>本节将介绍在触发器中最容易导致内存泄漏的三种情况：点、单位组和字符串。了解这些来源后，你就能在编写触发器时有意识地避免它们，让地图运行更流畅。</p><h3 id="什么是内存泄漏" tabindex="-1">什么是内存泄漏？ <a class="header-anchor" href="#什么是内存泄漏" aria-label="Permalink to “什么是内存泄漏？”">​</a></h3><p>内存就像你的工作台空间——当你创建一些东西（如一个点或一个单位组）时，相当于在桌上放了一个物品。用完后如果不清理，这个物品就会一直占用空间，直到地图关闭。内存泄漏就是指这些&quot;物品&quot;没有被正确清理，越积越多，最终导致游戏卡顿甚至崩溃。[^3]</p><h3 id="三种常见的泄漏来源" tabindex="-1">三种常见的泄漏来源 <a class="header-anchor" href="#三种常见的泄漏来源" aria-label="Permalink to “三种常见的泄漏来源”">​</a></h3><p><strong>1. 位置/点(Point)泄漏</strong></p><p>当你使用&quot;获取某单位的位置&quot;或&quot;获取某区域的中心点&quot;这类动作时，系统会在内存中创建一个<strong>点</strong>数据。如果你用完后没有&quot;清除点&quot;这个动作，这个点就会永远留在内存里。[^3]</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为变量被覆盖就等于清理了。实际上，你创建一个新的点变量时，旧的那个点仍然在内存中！必须专门用&quot;清除点&quot;动作来处理。</p></blockquote><p><strong>2. 单位组(Unit Group)泄漏</strong></p><p>&quot;单位组&quot;是一个可以装很多单位的&quot;篮子&quot;。当你用&quot;选择范围内所有单位&quot;或&quot;获取某玩家所有单位&quot;时，就会创建一个单位组。如果不用&quot;清除单位组&quot;动作，这个篮子以及里面所有单位的数据都会一直占用内存。[^3]</p><blockquote><p><strong>💡 新手提示</strong>：单位组泄漏比点泄漏更严重，因为一个单位组可能包含几十甚至上百个单位的数据。建议养成习惯——每创建一个单位组，就在用完后立即在同一条触发器中清除它。</p></blockquote><p><strong>3. 字符串(String)泄漏</strong></p><p>虽然不太常见，但字符串（如玩家输入的文字、动态生成的名称）也可能造成泄漏。当频繁修改同一个字符串变量时，旧的字符串内容可能没有被及时释放。[^3]</p><h3 id="如何识别泄漏" tabindex="-1">如何识别泄漏？ <a class="header-anchor" href="#如何识别泄漏" aria-label="Permalink to “如何识别泄漏？”">​</a></h3><p>在游戏中打开作弊命令 <code>-memleak</code> 可以查看是否有明显泄漏，但这只是辅助工具。更重要的是在编写触发器时就养成良好习惯。[^1]</p><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>现在你知道了三种主要的内存泄漏来源：点、单位组和字符串。记住一个原则——<strong>&quot;有创建就要有清除&quot;</strong>。下一节我们将学习如何用具体的触发器动作来修复这些泄漏。</p><h2 id="如何检测内存泄漏" tabindex="-1">如何检测内存泄漏 <a class="header-anchor" href="#如何检测内存泄漏" aria-label="Permalink to “如何检测内存泄漏”">​</a></h2><p>本节介绍如何发现你的触发器是否存在内存泄漏问题。学完本节后，你将能够通过观察游戏表现和使用测试方法来定位泄漏的触发器源头，避免地图越玩越卡。</p><h3 id="观察性能变化和游戏卡顿" tabindex="-1">观察性能变化和游戏卡顿 <a class="header-anchor" href="#观察性能变化和游戏卡顿" aria-label="Permalink to “观察性能变化和游戏卡顿”">​</a></h3><p>内存泄漏的典型症状是：游戏运行时间越长，反应越慢。一开始可能不明显，但如果你发现游戏玩了10分钟后开始卡顿，20分钟后几乎无法操作，这很可能就是内存泄漏在作怪[^3]。</p><p><strong>第一步：记录问题发生的时间点</strong></p><p>打开你的地图后，先正常游戏几分钟，记录下什么时候开始出现卡顿。每次重新加载地图，问题会重新出现，这说明不是电脑配置问题，而是地图本身存在泄漏。</p><p><strong>第二步：观察卡顿与特定操作的关联</strong></p><p>注意卡顿是在执行什么操作后开始加重的。比如刚进入游戏就卡，或者使用某个技能后才卡。特定操作触发泄漏的可能性更大，方便后续排查。</p><h3 id="使用测试地图进行排查" tabindex="-1">使用测试地图进行排查 <a class="header-anchor" href="#使用测试地图进行排查" aria-label="Permalink to “使用测试地图进行排查”">​</a></h3><p>创建一个小型的独立测试地图，每次只添加一个触发器，这样可以精确定位是哪个触发器在泄漏[^3]。</p><p><strong>第一步：新建空白测试地图</strong></p><p>打开World Editor，新建一个最小化的地图，只保留必要的地形和单位设置，不要添加任何触发器。运行几分钟确认没有卡顿，作为基准对照。</p><p><strong>第二步：逐个添加触发器测试</strong></p><p>将你怀疑有问题的触发器复制到测试地图中，运行5到10分钟观察是否出现卡顿。每次只测试一个触发器，如果出现问题就能锁定目标。</p><p><strong>第三步：记录并对比测试结果</strong></p><p>在测试地图中做好笔记，记录哪个触发器导致泄漏。这样即使地图很复杂，你也能清楚知道问题出在哪里。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手发现卡顿后，第一反应是怀疑电脑配置不够，而不是检查自己的触发器。实际上90%的卡顿问题都是内存泄漏导致的，只有在确认没有泄漏后才考虑优化其他代码。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：测试时可以在触发器中添加&quot;显示文字到游戏开始信息&quot;的本地化操作，比如显示&quot;触发器已执行&quot;，帮助你确认哪个触发器被激活了。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够通过观察游戏卡顿的时间规律，快速定位泄漏问题，并使用测试地图逐个排查触发器，最终找出罪魁祸首。</p><h2 id="修复内存泄漏的方法" tabindex="-1">修复内存泄漏的方法 <a class="header-anchor" href="#修复内存泄漏的方法" aria-label="Permalink to “修复内存泄漏的方法”">​</a></h2><p>本节将教你如何在触发器中使用&quot;清理函数&quot;来修复内存泄漏。学完本节后，你就能让你的地图即使运行很长时间也不会变卡！</p><hr><h3 id="清理位置-点变量-removelocation" tabindex="-1">清理位置/点变量 (RemoveLocation) <a class="header-anchor" href="#清理位置-点变量-removelocation" aria-label="Permalink to “清理位置/点变量 (RemoveLocation)”">​</a></h3><p>位置变量（也叫&quot;点&quot;变量）是内存泄漏最常见的来源之一。当你使用&quot;获取施法位置&quot;等动作创建了一个&quot;点&quot;之后，必须在使用完毕后手动销毁它。</p><p><strong>操作步骤：</strong></p><ol><li><p><strong>创建位置变量</strong> — 在触发器编辑器左侧，变量类型选择&quot;位置/点&quot;，新建一个变量（如 <code>TempPoint</code>）</p></li><li><p><strong>使用变量获取位置</strong> — 拖入&quot;获取某区域中心位置&quot;等动作，将结果存入 <code>TempPoint</code>[^3]</p></li><li><p><strong>使用完毕后添加清理动作</strong> — 在触发器末尾，添加&quot;自定义代码&quot;动作（Custom Script），输入以下内容：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call RemoveLocation(udg_TempPoint)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>⚠️ 注意：<code>udg_</code> 是变量的前缀，别写错了！</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手忘记添加清理动作，或者把清理动作放在了使用位置变量之前——这样根本起不到清理效果！清理动作必须<strong>放在所有使用该变量的动作之后</strong>。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：如果你在多个地方都用到了同一个位置变量，建议每次使用完就立即清理，而不是等到最后才清理，这样可以避免意外的错误。</p></blockquote><hr><h3 id="清理单位组变量-destroygroup" tabindex="-1">清理单位组变量 (DestroyGroup) <a class="header-anchor" href="#清理单位组变量-destroygroup" aria-label="Permalink to “清理单位组变量 (DestroyGroup)”">​</a></h3><p>单位组变量同样会产生内存泄漏。当你用&quot;选取单位&quot;等动作创建了一个单位组后，必须用 <code>DestroyGroup</code> 函数销毁它[^3]。</p><p><strong>操作步骤：</strong></p><ol><li><p><strong>创建单位组变量</strong> — 新建变量，类型选择&quot;单位组&quot;，命名为 <code>TempGroup</code></p></li><li><p><strong>使用变量获取单位组</strong> — 拖入&quot;选取区域内的单位&quot;等动作，将结果存入 <code>TempGroup</code>[^1]</p></li><li><p><strong>使用完毕后添加清理动作</strong> — 在触发器末尾添加&quot;自定义代码&quot;，输入：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call DestroyGroup(udg_TempGroup)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ol><blockquote><p><strong>💡 新手提示</strong>：清理单位组前，如果还需要对组内的单位进行操作，建议先用&quot;为单位组设置迭代器&quot;逐个处理每个单位，处理完后再销毁。销毁后千万不要再尝试使用这个变量！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：误以为把变量设为 <code>null</code>（空）就能释放内存——错！<code>null</code> 只是断开了引用，但内存中的数据仍然存在。必须用 <code>DestroyGroup</code> 才能真正释放。</p></blockquote><hr><h3 id="何时不需要清理变量" tabindex="-1">何时不需要清理变量 <a class="header-anchor" href="#何时不需要清理变量" aria-label="Permalink to “何时不需要清理变量”">​</a></h3><p>并不是所有变量都需要手动清理！了解何时不需要清理，可以让你少走很多弯路。</p><p><strong>以下情况不需要清理：</strong></p><ul><li><strong>动态获取的单位/物品/魔法效果</strong> — 游戏系统会自动管理，比如&quot;触发单位&quot;、&quot;死亡单位&quot;等系统变量</li><li><strong>在触发器开始时就设置好的静态变量</strong> — 如果一个变量从地图开始就存在且一直用，不会产生新的泄漏</li><li><strong>使用&quot;泄漏最小化&quot;的替代方案</strong> — 比如尽量复用同一个位置变量，而不是每次都创建新的[^1]</li></ul><blockquote><p><strong>💡 新手提示</strong>：如果你不确定某个变量是否需要清理，就想想：这个变量是不是在每次触发执行时都会&quot;新建&quot;一个值？如果是，那就需要清理。</p></blockquote><hr><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的触发器就能正确地清理临时创建的位置和单位组了。养成<strong>每次创建就清理</strong>的好习惯，你的地图即使运行一整天也能保持流畅！记得在所有&quot;获取位置&quot;和&quot;选取单位&quot;的动作后面，都补上对应的清理代码。</p><h2 id="触发器编写最佳实践" tabindex="-1">触发器编写最佳实践 <a class="header-anchor" href="#触发器编写最佳实践" aria-label="Permalink to “触发器编写最佳实践”">​</a></h2><p>本节将学习如何编写高效的触发器代码，避免内存泄漏问题。完成学习后，你将能够编写出运行流畅、不会让地图变卡的触发器。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>理解什么是内存泄漏</strong> — 内存泄漏是指触发器创建了游戏对象（如特效、单位、浮空文字）后，忘记将它们从游戏中移除，导致内存被占用且无法回收[^1]。想象你每次打开衣柜拿衣服却从不关柜门，衣柜迟早会塞满。内存泄漏就是这个道理，地图运行时间越长，卡顿越严重。</p></li><li><p><strong>为所有创建的特效添加销毁动作</strong> — 当你使用&quot;创建特效&quot;动作时，必须在不需要时使用&quot;销毁特效&quot;动作[^3]。例如在触发器末尾或触发器再次运行时，先销毁旧特效再创建新特效。</p></li><li><p><strong>使用&quot;最后创建的特效&quot;变量保存引用</strong> — 创建特效后，立即将其赋值给一个变量（如<code>TempEffect</code>），这样你才能在之后精准销毁它[^3]。不要创建后就丢掉引用，否则你将无法销毁它。</p></li><li><p><strong>养成&quot;创建必销毁&quot;的习惯</strong> — 每当你写一个触发器创建了游戏对象，就在同一触发器中规划好销毁时机[^3]。可以在触发器开头销毁旧对象，或在触发器结束时清理。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：养成好习惯——每当你写&quot;创建&quot;类动作时，立刻在脑海中问自己：&quot;这个对象什么时候销毁？&quot;</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常在&quot;每X秒执行&quot;触发器中反复创建特效却不销毁。短期内看不出问题，但地图运行几分钟后就会开始卡顿。解决方法是在创建新特效前，先检查变量是否不为空，如果不为空则销毁旧特效。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的触发器将更加高效稳定。记住核心原则：<strong>&quot;有创建必有销毁&quot;</strong>。这是一个看似简单但极其重要的习惯，养成它，你的地图就能远离卡顿困扰。</p><h2 id="实例演示与练习" tabindex="-1">实例演示与练习 <a class="header-anchor" href="#实例演示与练习" aria-label="Permalink to “实例演示与练习”">​</a></h2><p>本节将通过两个具体例子，带你亲手修复触发器中的内存泄漏。学完之后，你将能够发现地图中常见的泄漏问题，并学会用正确的方法清理它们。</p><h3 id="基础泄漏修复示例" tabindex="-1">基础泄漏修复示例 <a class="header-anchor" href="#基础泄漏修复示例" aria-label="Permalink to “基础泄漏修复示例”">​</a></h3><p>让我们从一个最常见的问题开始：<strong>漂浮文字（Floating Text）的泄漏</strong>。漂浮文字是很多RPG地图用来显示伤害数字的效果，但如果每次伤害都创建新的漂浮文字而不销毁它们，内存就会越积越多。</p><ol><li><p><strong>打开触发编辑器</strong> — 在WE顶部菜单点击&quot;触发器&quot;按钮，打开触发编辑器窗口[^1]</p></li><li><p><strong>找到你的伤害触发</strong> — 在左侧触发列表中找到显示伤害数字的触发（通常命名为&quot;显示伤害&quot;或类似名称）</p></li><li><p><strong>在触发末尾添加&quot;销毁漂浮文字&quot;动作</strong> — 展开&quot;文本&quot;类别，将&quot;销毁漂浮文字&quot;动作拖到你的伤害文字创建动作之后[^1]</p></li><li><p><strong>使用变量保存漂浮文字</strong> — 如果你还没有用变量保存漂浮文字，需要先创建一个&quot;漂浮文字&quot;类型的变量，然后在创建时&quot;设置变量&quot;为该文字，再用完后再销毁</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：记得是&quot;销毁漂浮文字&quot;而不是&quot;隐藏漂浮文字&quot;。&quot;隐藏&quot;只是看不见了，但内存中的对象仍然存在！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只记得创建漂浮文字，忘了在伤害数字显示完毕后立即销毁。检查你的触发逻辑，确保每创建一个漂浮文字，就一定有一条对应的销毁命令。</p></blockquote><h3 id="复杂场景的解决方案" tabindex="-1">复杂场景的解决方案 <a class="header-anchor" href="#复杂场景的解决方案" aria-label="Permalink to “复杂场景的解决方案”">​</a></h3><p>当你处理<strong>单位组（Unit Group）</strong>时，泄漏问题更隐蔽。单位组是保存多个单位引用的容器，如果不及时清理，地图会越来越卡。</p><p><strong>典型泄漏场景</strong>：每帧检测范围内敌人时，都用&quot;枚举区域内的单位&quot;创建一个新组，但从不销毁。</p><p><strong>解决方案</strong>：</p><ol><li>为单位组创建专用变量（类型：单位组）</li><li>每次使用&quot;枚举区域内的单位&quot;后，立即在触发末尾添加&quot;清除单位组&quot;动作[^3]</li></ol><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// JASS代码示例（高级用法，可参考）</span></span>
<span class="line"><span>call DestroyGroup(udg_你的单位组变量)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p><strong>💡 新手提示</strong>：GUI界面中&quot;清除单位组&quot;和&quot;销毁单位组&quot;有区别。&quot;清除&quot;是清空组内的单位但保留组本身，&quot;销毁&quot;是完全删除这个组。对于重复使用的组，用&quot;清除&quot;就够了。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上两个练习后，你应该已经掌握了处理触发器内存泄漏的核心方法：</p><ul><li>记住&quot;有创建就必须有销毁&quot;的原则</li><li>使用变量保存需要管理的对象</li><li>在触发末尾添加清理动作</li></ul><p>建议现在打开你的地图，找到任意一个创建了视觉效果（如爆炸、漂浮文字、单位组）的触发，尝试为它添加相应的销毁代码，亲手感受一下修复过程！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.thehelper.net/threads/floating-text-leaks.129373/" target="_blank" rel="noreferrer">Floating text leaks | The Helper</a> — accessed 2026-05-08 [^3]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=27219" target="_blank" rel="noreferrer">Memory Leaks and Custom Scripts - Warcraft III World Editor</a> — accessed 2026-05-08</p>`,109)])])}const c=t(s,[["render",l]]);export{d as __pageData,c as default};
